import json
# Count shapes and configs per dataset
for ds in ['dataset0206', 'dataset0210', 'dataset0211']:
    for split in ['train', 'val', 'test']:
        import os, glob
        base = f'/local/nick/ai_iree/{ds}/{split}'
        if not os.path.isdir(base):
            continue
        reports = glob.glob(f'{base}/compile_report*.json')
        total_shapes = 0
        total_pass = 0
        total_configs = 0
        has_bench = 0
        for rp in reports:
            r = json.load(open(rp))
            for op, shapes in r.items():
                for sk, sd in shapes.items():
                    total_shapes += 1
                    bl = sd.get('baseline', {})
                    if bl.get('compile') == 'PASS':
                        total_configs += 1
                    if 'benchmark' in bl:
                        has_bench += 1
                    for cfg in sd.get('lowering_configs', []):
                        if cfg.get('compile') == 'PASS':
                            total_configs += 1
        print(f'{ds}/{split}: {total_shapes} shapes, {total_configs} PASS configs, {has_bench} with benchmark')
" 2>/dev/null

