                total += 1
                bl = sd.get('baseline', {})
                if 'benchmark' in bl:
                    has_bench += 1
                for cfg in sd.get('lowering_configs', []):
                    if cfg.get('benchmark') == 'P' and cfg.get('latency_ns'):
                        pass_with_latency += 1
            print(f'{os.path.basename(rp)} ({split}): {has_bench}/{total} shapes benchmarked, {pass_with_latency} P configs with latency')
