# Check what percentage of configs have benchmark P status in dataset0206
import json, glob
for split in ['train']:
    base = f'/local/nick/ai_iree/dataset0206/{split}'
    reports = glob.glob(f'{base}/compile_report_worker_*.json')
    total_pass_compile = 0
    total_bench_p = 0
    total_bench_t = 0
    total_bench_f = 0
    total_no_bench = 0
    for rp in reports:
        r = json.load(open(rp))
        for op, shapes in r.items():
            for sk, sd in shapes.items():
                for entry in [sd.get('baseline', {})] + sd.get('lowering_configs', []):
                    if entry.get('compile') == 'PASS':
                        total_pass_compile += 1
                        b = entry.get('benchmark')
                        if b == 'P':
                            total_bench_p += 1
                        elif b == 'T':
                            total_bench_t += 1
                        elif b == 'F':
                            total_bench_f += 1
                        else:
                            total_no_bench += 1
    print(f'dataset0206/{split}: compile_PASS={total_pass_compile}, bench_P={total_bench_p}, bench_T={total_bench_t}, bench_F={total_bench_f}, no_bench={total_no_bench}')
" 2>/dev/null
